// PromoLinkHandler.swift
import Foundation

struct PromoLinkHandler {

    static func handle(url: URL) {
        guard url.path.lowercased().hasPrefix("/promo") else { return }
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false) else { return }

        let promoCode = components.queryItemValue(named: "code")
        let discountStr = components.queryItemValue(named: "discount")

        guard let code = promoCode,
              let discountText = discountStr,
              let discount = Int(discountText) else { return }

        PromoManager.applyPromo(code: code, discount: discount)
    }
}

// URLComponents+QueryItem.swift
import Foundation

extension URLComponents {
    func queryItemValue(named name: String) -> String? {
        queryItems?.first(where: { $0.name.caseInsensitiveCompare(name) == .orderedSame })?.value
    }
}

// PromoManager.swift
import Foundation

struct PromoManager {

    static func applyPromo(code: String, discount: Int) {
        guard let account = UserAccount.current else { return }
        NetworkService.redeemPromo(code: code, discount: discount) { success in
            if success {
                account.apply(discount: discount, promoCode: code)
            }
        }
    }
}

// NetworkService.swift
import Foundation

enum NetworkService {

    static func redeemPromo(code: String,
                            discount: Int,
                            completion: @escaping (Bool) -> Void) {
        guard let url = URL(string: "https://api.myapp.com/redeem") else {
            completion(false)
            return
        }

        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        let body: [String: Any] = ["code": code, "discount": discount]
        request.httpBody = try? JSONSerialization.data(withJSONObject: body)

        URLSession.shared.dataTask(with: request) { _, response, error in
            let success = (response as? HTTPURLResponse)?.statusCode == 200 && error == nil
            completion(success)
        }.resume()
    }
}

// UserAccount.swift
import Foundation

class UserAccount {

    static var current: UserAccount?

    private(set) var activePromos: [String: Int] = [:]

    func apply(discount: Int, promoCode: String) {
        activePromos[promoCode] = discount
        NotificationCenter.default.post(name: .promoApplied,
                                        object: nil,
                                        userInfo: ["code": promoCode, "discount": discount])
    }
}

